'use client';

import { AdminNav } from '@/components/AdminNav';
import { RequireAuth } from '@/components/RequireAuth';
import { adminApi } from '@/lib/api';
import { useEffect, useState } from 'react';

export default function TablesPage() {
  const [items, setItems] = useState<any[]>([]);
  const [tableCode, setTableCode] = useState('A2');
  const [tableName, setTableName] = useState('Table A2');

  async function load() {
    const r = await adminApi.tables();
    setItems(r.items);
  }

  useEffect(() => { load(); }, []);

  return (
    <RequireAuth>
      <main>
        <AdminNav />
        <div className="card">
          <h1>Tables</h1>
          <div className="grid2">
            <input value={tableCode} onChange={(e) => setTableCode(e.target.value)} placeholder="Code" />
            <input value={tableName} onChange={(e) => setTableName(e.target.value)} placeholder="Name" />
          </div>
          <div style={{ marginTop: 10 }}>
            <button onClick={async () => { await adminApi.upsertTable({ table_code: tableCode, table_name: tableName, rotate_qr: true }); await load(); }}>Save + Rotate QR</button>
          </div>
        </div>
        {items.map((t) => (
          <div className="card" key={t.id}>
            <b>{t.table_code}</b> - {t.table_name}
            <div className="small">Active: {String(t.is_active)} | Token: {t.qr_token}</div>
          </div>
        ))}
      </main>
    </RequireAuth>
  );
}
